class BaseTask:
    def __init__(self, title, priority):
        if title.strip() == "":
            raise ValueError("title cannot be empty")
        if priority not in ["low", "medium", "high"]:
            raise ValueError("invalid priority")
        self._title = title
        self._priority = priority

    def get_title(self):
        return self._title

    def get_priority(self):
        return self._priority

    def get_effort_score(self):
        raise NotImplementedError("subclasses must implement get_effort_score")

    def describe(self):
        raise NotImplementedError("subclasses must implement describe")


class BugTask(BaseTask):
    def __init__(self, title, priority, severity):
        super().__init__(title, priority)
        if severity < 1:
            raise ValueError("severity must be at least 1")
        self._severity = severity

    def get_effort_score(self):
        return self._severity * 2

    def describe(self):
        return f"BUG | {self.get_title()} | {self.get_priority()} | severity {self._severity}"


class FeatureTask(BaseTask):
    def __init__(self, title, priority, estimate):
        super().__init__(title, priority)
        if estimate < 1:
            raise ValueError("estimate must be at least 1")
        self._estimate = estimate

    def get_effort_score(self):
        return self._estimate

    def describe(self):
        return f"FEATURE | {self.get_title()} | {self.get_priority()} | estimate {self._estimate}"


class TaskService:
    def __init__(self):
        self._tasks = []

    def add_task(self, task):
        self._tasks.append({"title": task.get_title(), "priority": task.get_priority()})

    def count_tasks(self):
        return len(self._tasks)

    def total_effort(self):
        total = 0
        for task in self._tasks:
            total += task["effort"]
        return total

    def titles_by_priority(self, priority):
        matches = []
        for task in self._tasks:
            if task["priority"] == priority:
                matches.append(task["title"])
        return matches

    def build_report_lines(self):
        lines = ["Smart Task Tracker Report"]
        lines.append(f"Total tasks: {self.count_tasks()}")
        lines.append(f"Total effort: {self.total_effort()}")
        for task in self._tasks:
            lines.append(task["title"])
        return lines

